#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int countVectors(int N, int S[], int X[]) {
    int count = 0;
    for (uint64_t i = 0; i < (1ULL << (N * 18)); i++) {
        uint64_t vec[N];
        for (int j = 0; j < N; j++) {
            vec[j] = (i >> (j * 18)) & ((1ULL << 18) - 1);
        }
        int valid = 1;
        for (int j = 0; j < N; j++) {
            if (S[j] == 1 && vec[j] < X[j]) {
                valid = 0;
                break;
            }
            if (S[j] == 0 && vec[j] > X[j]) {
                valid = 0;
                break;
            }
        }
        if (valid) {
            char str[100];
            sprintf(str, "%llu", i);
            if (strstr(str, "47") != NULL) {
                count++;
            }
        }
    }
    return count % MOD;
}

int main() {
    int N;
    scanf("%d", &N);
    int S[N], X[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &S[i], &X[i]);
    }
    printf("%d\n", countVectors(N, S, X));
    return 0;
}

